from collections import deque

def max_flow(capacity, s, t, n):
    residual = [row[:] for row in capacity]
    total_flow = 0

    while True:
        # BFS to find augmenting path
        parent = [-1] * n
        visited = [False] * n
        visited[s] = True
        queue = deque([s])

        while queue:
            u = queue.popleft()
            for v in range(n):
                if not visited[v] and residual[u][v] > 0:
                    visited[v] = True
                    parent[v] = u
                    if v == t:
                        break
                    queue.append(v)

        if not visited[t]:
            break

        # Find bottleneck
        path_flow = float('inf')
        v = t
        while v != s:
            u = parent[v]
            path_flow = min(path_flow, residual[u][v])
            v = u

        # Update residual graph
        v = t
        while v != s:
            u = parent[v]
            residual[u][v] -= path_flow
            residual[v][u] += path_flow
            v = u

        total_flow += path_flow

    return total_flow
